package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonCodeCalculator;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.AardKodeExtensieReferentieJaarKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.Indexator;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.KedefFormuletype;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.Multimap;
import lombok.AllArgsConstructor;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INDEXATOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.RKM_COREHR_CONFIG_MANAGER;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SUPPLEMENTEN_KEY;

@AllArgsConstructor
public class BerekenSupplementen {

    private static final int SCALE = 2;

    private final NlpGlobalService globalService;
    private final ConstantManager constantManager;
    private final LoonElementVerwerker loonElementVerwerker;

    public void bereken(RekenContext context, Opdracht opdracht) {
        Set<LoonElement> supplementenFase1 = berekenSupplementen(context, opdracht, null);
        berekenSupplementen(context, opdracht, supplementenFase1);
    }

    private Set<LoonElement> berekenSupplementen(RekenContext context, Opdracht opdracht, Set<LoonElement> supplementenFase1) {
        boolean fase2 = supplementenFase1 != null;
        Set<LoonElement> supplementenFaseNu = LoonElement.createSortedSet();
        LoonElementManager manager = context.getLoonElementManager();
        RekenTijd rekenTijd = context.getRekenTijd();
        RegulManager regulManager = context.getRegulManager();
        LoonCodeManager loonCodeManager = context.getLoonCodeManager();
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = context.getUnchecked(RKM_COREHR_CONFIG_MANAGER);
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(opdracht, rekenTijd);
        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        LoonCodeCalculatorFactory factory = new LoonCodeCalculatorFactory(constantManager, regulManager, loonCodeManager, globalService, rkmCoreHrConfiguratie);
        for (Opper opper : opdracht.getOpperSlices()) {
            List<NlpPrestatie> supplementen = context.getDoubleKey(SUPPLEMENTEN_KEY, opper);
            Multimap<AardKodeExtensieReferentieJaarKey, NlpPrestatie> looncodeToSupplementen =
                    maakLoonCodeToSupplementenMap(loonCodeManager, supplementen, fase2);
            for (AardKodeExtensieReferentieJaarKey key : looncodeToSupplementen.keySet()) {
                AardKodeExtensie loonCode = key.getAardKodeExtensie();
                Collection<NlpPrestatie> lijst = looncodeToSupplementen.get(key);
                BigDecimal index = indexator.bepaalIndex(opper);
                LoonCodeCalculator calculator = factory.genereerLoonCodeCalculator(opper, loonCode, rekenTijd, supplementenFase1, index);
                LoonElement element = berekenSuplement(context, loonCode, opper, rekenTijd, calculator, key.getReferentieJaar(), lijst);
                manager.addLoonElement(element, opper);
                supplementenFaseNu.add(element);
            }
        }
        return supplementenFaseNu;
    }

    private Multimap<AardKodeExtensieReferentieJaarKey, NlpPrestatie> maakLoonCodeToSupplementenMap(
            LoonCodeManager loonCodeManager, List<NlpPrestatie> supplementen, boolean fase2) {
        Multimap<AardKodeExtensieReferentieJaarKey, NlpPrestatie> looncodeToSupplementen = ArrayListMultimap.create();
        for (NlpPrestatie supplement : supplementen) {
            AardKodeExtensie loonCode =
                    loonCodeManager.getByTake(supplement.getTijdperk(), AardKodeExt.S_KODE_EXT.getCode(), supplement.getCode(), supplement.getExtensie());
            Integer referentieJaar = supplement.getReferentieJaar();
            if (referentieJaar != null && referentieJaar == 0) {
                referentieJaar = null;
            }
            boolean isSupplementFase2 = loonCode.getFormuleType() == KedefFormuletype.ONR_WG_UL && loonCode.getConst3nr() != 0;
            if (isSupplementFase2 == fase2) {
                looncodeToSupplementen.put(new AardKodeExtensieReferentieJaarKey(loonCode, referentieJaar), supplement);
            }
        }
        return looncodeToSupplementen;
    }

    private LoonElement berekenSuplement(
            RekenContext context, AardKodeExtensie loonCode, Opper opper, RekenTijd rekenTijd,
            LoonCodeCalculator calculator, Integer referentieJaar, Collection<NlpPrestatie> lijst) {
        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        Money totaalBedrag = Money.ZERO;
        for (NlpPrestatie supplement : lijst) {
            Money bedrag = calculator.berekenBedrag100Percent(supplement.getY());

            bedrag = indexator.indexeer(bedrag, loonCode, opper);
            bedrag = bedrag.multiply(supplement.getX());
            totaalBedrag = totaalBedrag.add(bedrag);
        }
        totaalBedrag = totaalBedrag.round(SCALE);
        LoonElement element = new LoonElement(loonCode);
        element.setReferentieJaar(referentieJaar);
        if (BrutoTools.heeftBassi(element.getAardKodeExtensie(), opper.getOpdracht().getHoedanigheid())) {
            Money bassi = loonElementVerwerker.verhogingBassi(totaalBedrag, opper, rekenTijd);
            element.putProperty(BASIS_SOCIALE_INHOUDINGEN_KEY, bassi);
        }
        if (!element.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.ERKENT_PREMIE_OF_WG_BIJDR_GROEPSVERZ_KEY) && !element.getAardKodeExtensie()
                .behoortTotGroep(LooncodeGroepKeyStrings.SUPPLEMENT_MET_ENKEL_BASSI_KEY)) {
            element.putProperty(BRUTO_MAANDLOON_KEY, totaalBedrag);
        }
        return element;
    }
}
